const history = $input.first().json || {};
const strategy = $('Load backtest strategies').item.json;
const prices = (history.prices || []).map((row) => ({ time: row[0], price: Number(row[1]) })).filter((row) => Number.isFinite(row.price));
const volumes = (history.total_volumes || []).map((row) => Number(row[1])).filter((value) => Number.isFinite(value));
const conditions = strategy.conditions || {};
const accountSize = 10000;
const riskAmount = accountSize * (Number(strategy.riskPercent || 0.25) / 100);
const maxHoldBars = 8;

function ema(values, period) {
  if (!period || values.length < period) return null;
  let result = values.slice(0, period).reduce((sum, value) => sum + value, 0) / period;
  const multiplier = 2 / (period + 1);
  for (let index = period; index < values.length; index += 1) result = (values[index] - result) * multiplier + result;
  return result;
}

function rsi(values, period = 14) {
  if (values.length < period + 1) return null;
  let gains = 0;
  let losses = 0;
  for (let index = 1; index <= period; index += 1) {
    const diff = values[index] - values[index - 1];
    if (diff >= 0) gains += diff;
    else losses -= diff;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;
  for (let index = period + 1; index < values.length; index += 1) {
    const diff = values[index] - values[index - 1];
    if (diff >= 0) {
      avgGain = (avgGain * (period - 1) + diff) / period;
      avgLoss = (avgLoss * (period - 1)) / period;
    } else {
      avgGain = (avgGain * (period - 1)) / period;
      avgLoss = (avgLoss * (period - 1) - diff) / period;
    }
  }
  if (avgLoss === 0) return 100;
  return 100 - (100 / (1 + avgGain / avgLoss));
}

function macd(values) {
  if (values.length < 52) return null;
  const current = ema(values, 12) - ema(values, 26);
  const previousValues = values.slice(0, -1);
  const previous = ema(previousValues, 12) - ema(previousValues, 26);
  return { bullish: current > 0 && current > previous };
}

function volumeSpike(values, index, lookback = 20) {
  if (index < lookback || values.length <= index) return 1;
  const recent = values.slice(index - lookback, index);
  const avg = recent.reduce((sum, value) => sum + value, 0) / recent.length;
  return avg > 0 ? values[index] / avg : 1;
}

function signalAt(index) {
  const slice = prices.slice(0, index + 1).map((row) => row.price);
  const current = slice.at(-1);
  const emaPeriod = conditions.price_above_ema || conditions.price_below_ema;
  const emaValue = ema(slice, emaPeriod);
  const rsiValue = (conditions.rsi_above || conditions.rsi_below) ? rsi(slice) : null;
  const macdValue = (conditions.macd_bullish || conditions.macd_bearish) ? macd(slice) : null;
  const volSpike = conditions.volume_spike ? volumeSpike(volumes, index) : 1;

  if (conditions.price_above_ema && !(emaValue !== null && current > emaValue)) return false;
  if (conditions.price_below_ema && !(emaValue !== null && current < emaValue)) return false;
  if (conditions.rsi_above && !(rsiValue !== null && rsiValue > conditions.rsi_above)) return false;
  if (conditions.rsi_below && !(rsiValue !== null && rsiValue < conditions.rsi_below)) return false;
  if (conditions.macd_bullish && !(macdValue && macdValue.bullish)) return false;
  if (conditions.volume_spike && volSpike < conditions.volume_spike) return false;
  return true;
}

const trades = [];
let balance = accountSize;
let equityPeak = accountSize;
let maxDrawdown = 0;
let cursor = 60;

while (cursor < prices.length - maxHoldBars - 1) {
  if (!signalAt(cursor)) {
    cursor += 1;
    continue;
  }
  const entry = prices[cursor].price;
  const stop = entry * Number(strategy.slPercent || 0.98);
  const target = entry * Number(strategy.tpPercent || 1.02);
  const unitRisk = Math.max(Math.abs(entry - stop), 1);
  const size = riskAmount / unitRisk;
  let exit = prices[cursor + maxHoldBars].price;
  let exitReason = 'time_exit';

  for (let offset = 1; offset <= maxHoldBars; offset += 1) {
    const price = prices[cursor + offset].price;
    if (strategy.direction === 'LONG' && price <= stop) {
      exit = stop;
      exitReason = 'stop_loss';
      break;
    }
    if (strategy.direction === 'LONG' && price >= target) {
      exit = target;
      exitReason = 'take_profit';
      break;
    }
  }

  const pnl = (exit - entry) * size;
  balance += pnl;
  equityPeak = Math.max(equityPeak, balance);
  maxDrawdown = Math.max(maxDrawdown, equityPeak - balance);
  trades.push({ entryTime: prices[cursor].time, entry, exit, exitReason, pnl: Number(pnl.toFixed(2)) });
  cursor += maxHoldBars;
}

const wins = trades.filter((trade) => trade.pnl > 0);
const losses = trades.filter((trade) => trade.pnl <= 0);
const grossWin = wins.reduce((sum, trade) => sum + trade.pnl, 0);
const grossLoss = Math.abs(losses.reduce((sum, trade) => sum + trade.pnl, 0));
return [{
  json: {
    strategy_id: strategy.id,
    symbol: strategy.symbol,
    trades: trades.length,
    wins: wins.length,
    losses: losses.length,
    win_rate: trades.length ? Number(((wins.length / trades.length) * 100).toFixed(2)) : 0,
    net_pnl: Number((balance - accountSize).toFixed(2)),
    ending_balance: Number(balance.toFixed(2)),
    profit_factor: grossLoss > 0 ? Number((grossWin / grossLoss).toFixed(2)) : grossWin > 0 ? 99 : 0,
    max_drawdown: Number(maxDrawdown.toFixed(2)),
    sample_trades: trades.slice(-5),
    source: 'n8n-backtest-simulation',
    note: 'Research only. This is not permission for live execution.'
  }
}];
